'use client'

import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import JobCard from '@/components/JobCard'
import CreateJobForm from '@/components/CreateJobForm'
import type { Job } from '@/lib/types'

export default function JobsPage() {
  const [jobs, setJobs] = useState<Job[]>([])
  const [viewerContractorId, setViewerContractorId] = useState<string | null>(null)
  const [viewerIsGC, setViewerIsGC] = useState(false)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    async function load() {
      const { data: { session } } = await supabase.auth.getSession()

      if (session?.user) {
        const { data: contractor } = await supabase
          .from('contractors')
          .select('id, trade')
          .eq('user_id', session.user.id)
          .eq('status', 'approved')
          .maybeSingle()

        if (contractor) {
          setViewerContractorId(contractor.id)
          setViewerIsGC(contractor.trade === 'General Contractor')
        }
      }

      const { data: jobsData } = await supabase
        .from('jobs')
        .select(`
          id, title, description, trade, location_city, location_state,
          status, created_at, hired_at, completed_at, gc_contractor_id, hired_contractor_id,
          gc_contractor:contractors!jobs_gc_contractor_id_fkey(full_name, trade),
          hired_contractor:contractors!jobs_hired_contractor_id_fkey(full_name, trade)
        `)
        .order('created_at', { ascending: false })
        .limit(50)

      setJobs((jobsData as unknown as Job[]) ?? [])
      setLoading(false)
    }

    load()
  }, [])

  return (
    <div className="mx-auto max-w-2xl px-4 py-10 sm:px-6">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-slate-100">Jobs Board</h1>
        <p className="mt-1 text-slate-400">
          Subcontracting opportunities posted by verified General Contractors
        </p>
      </div>

      {viewerIsGC && viewerContractorId && (
        <CreateJobForm gcContractorId={viewerContractorId} />
      )}

      {loading ? (
        <div className="rounded-lg border border-slate-800 bg-slate-900/50 px-5 py-8 text-center">
          <p className="text-sm text-slate-400">Loading...</p>
        </div>
      ) : jobs.length === 0 ? (
        <div className="rounded-lg border border-slate-800 bg-slate-900/50 px-5 py-8 text-center">
          <p className="text-sm text-slate-400">
            No jobs posted yet. GCs can post subcontracting opportunities here.
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {jobs.map((job) => (
            <JobCard
              key={job.id}
              job={job}
              isOwner={job.gc_contractor_id === viewerContractorId}
            />
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useState } from 'react'
import type { Job, JobStatus } from '@/lib/types'
import { markCompleted } from '@/app/jobs/actions'
import SubSelectorModal from '@/components/SubSelectorModal'

interface JobCardProps {
  job: Job
  isOwner: boolean
}

const statusConfig: Record<JobStatus, { label: string; className: string }> = {
  open:      { label: 'Open',      className: 'bg-emerald-900/50 text-emerald-400' },
  hired:     { label: 'Hired',     className: 'bg-amber-900/40 text-amber-400' },
  completed: { label: 'Completed', className: 'bg-slate-800 text-slate-400' },
}

function formatDate(dateStr: string): string {
  const date = new Date(dateStr)
  const now = new Date()
  const diffMs = now.getTime() - date.getTime()
  const diffHours = Math.floor(diffMs / (1000 * 60 * 60))
  const diffDays = Math.floor(diffHours / 24)

  if (diffHours < 1) return 'Just now'
  if (diffHours < 24) return `${diffHours}h ago`
  if (diffDays < 7) return `${diffDays}d ago`
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

export default function JobCard({ job, isOwner }: JobCardProps) {
  const [showModal, setShowModal] = useState(false)
  const [completing, setCompleting] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const status = statusConfig[job.status]
  const location = [job.location_city, job.location_state].filter(Boolean).join(', ')

  async function handleMarkCompleted() {
    if (!job.hired_contractor_id) return
    setCompleting(true)
    setError(null)
    try {
      await markCompleted(job.id, job.hired_contractor_id)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to mark complete')
    } finally {
      setCompleting(false)
    }
  }

  return (
    <div className="rounded-lg border border-slate-800 bg-slate-900 p-5">
      <div className="flex items-start justify-between gap-3">
        <div className="flex-1 min-w-0">
          <h3 className="text-base font-bold text-slate-100 truncate">{job.title}</h3>
          <p className="mt-0.5 text-sm text-slate-400">
            {job.trade}
            {location ? ` · ${location}` : ''}
          </p>
          {job.gc_contractor && (
            <p className="mt-0.5 text-xs text-slate-500">
              Posted by {job.gc_contractor.full_name}
            </p>
          )}
        </div>
        <div className="flex flex-col items-end gap-1.5 shrink-0">
          <span className={`rounded-full px-2 py-0.5 text-xs font-medium ${status.className}`}>
            {status.label}
          </span>
          <span className="text-xs text-slate-500">{formatDate(job.created_at)}</span>
        </div>
      </div>

      {job.description && (
        <p className="mt-3 text-sm text-slate-300 line-clamp-3">{job.description}</p>
      )}

      {job.status === 'hired' && job.hired_contractor && (
        <p className="mt-2 text-xs text-slate-500">
          Hired: {job.hired_contractor.full_name}
        </p>
      )}

      {error && (
        <p className="mt-2 text-xs text-red-400">{error}</p>
      )}

      {isOwner && (
        <div className="mt-4">
          {job.status === 'open' && (
            <>
              <button
                onClick={() => setShowModal(true)}
                className="rounded-md bg-amber-500 px-3 py-1.5 text-sm font-semibold text-slate-950 hover:bg-amber-400 transition-colors"
              >
                Mark Hired
              </button>
              {showModal && (
                <SubSelectorModal
                  jobId={job.id}
                  onClose={() => setShowModal(false)}
                />
              )}
            </>
          )}
          {job.status === 'hired' && (
            <button
              onClick={handleMarkCompleted}
              disabled={completing}
              className="rounded-md bg-slate-700 px-3 py-1.5 text-sm font-semibold text-slate-200 hover:bg-slate-600 transition-colors disabled:opacity-50"
            >
              {completing ? 'Completing...' : 'Mark Complete'}
            </button>
          )}
        </div>
      )}
    </div>
  )
}

'use server'

import { revalidatePath } from 'next/cache'
import { getSupabaseAdmin } from '@/lib/supabase-admin'

interface CreateJobData {
  gc_contractor_id: string
  title: string
  description: string
  trade: string
  location_city: string | null
  location_state: string | null
}

export async function createJob(data: CreateJobData) {
  const admin = getSupabaseAdmin()
  const { error } = await admin.from('jobs').insert({
    ...data,
    status: 'open',
  })
  if (error) throw new Error(error.message)
  revalidatePath('/jobs')
}

export async function markHired(jobId: string, hiredContractorId: string) {
  const admin = getSupabaseAdmin()
  const { error } = await admin
    .from('jobs')
    .update({
      status: 'hired',
      hired_contractor_id: hiredContractorId,
      hired_at: new Date().toISOString(),
    })
    .eq('id', jobId)
  if (error) throw new Error(error.message)
  revalidatePath('/jobs')
}

export async function markCompleted(jobId: string, hiredContractorId: string) {
  const admin = getSupabaseAdmin()
  const { error } = await admin
    .from('jobs')
    .update({
      status: 'completed',
      completed_at: new Date().toISOString(),
    })
    .eq('id', jobId)
  if (error) throw new Error(error.message)
  revalidatePath('/jobs')
  revalidatePath(`/contractors/${hiredContractorId}`)
}

interface CompletedJob {
  id: string
  title: string
  trade: string
  location_city: string | null
  location_state: string | null
  completed_at: string | null
  gc_contractor?: { full_name: string } | null
}

interface CompletedJobsSectionProps {
  jobs: CompletedJob[]
}

export default function CompletedJobsSection({ jobs }: CompletedJobsSectionProps) {
  if (jobs.length === 0) return null

  return (
    <section className="rounded-lg border border-slate-800 bg-slate-900 p-6">
      <h2 className="text-xs font-semibold uppercase tracking-wider text-slate-400">
        Verified Work History
      </h2>
      <p className="text-xs text-slate-500 mb-4">Platform-verified completed jobs</p>

      <div>
        {jobs.map((job) => (
          <div
            key={job.id}
            className="border-t border-slate-800 py-3 first:border-t-0 first:pt-0"
          >
            <p className="font-semibold text-slate-100 text-sm">{job.title}</p>
            <p className="text-xs text-slate-400 mt-0.5">
              Hired by {job.gc_contractor?.full_name ?? 'Unknown'}
            </p>
            <p className="text-xs text-slate-500 mt-1">
              {job.trade}
              {job.location_city ? ` · ${job.location_city}, ${job.location_state}` : ''} · Completed{' '}
              {job.completed_at
                ? new Date(job.completed_at).toLocaleDateString('en-US', {
                    month: 'short',
                    year: 'numeric',
                  })
                : 'recently'}
            </p>
          </div>
        ))}
      </div>
    </section>
  )
}

